const now = new Date();
const day = now.getDay(); // 0=Sun, 6=Sat

// Skip weekends
if (day === 0 || day === 6) {
  return []; // halt workflow
}

const pad = n => String(n).padStart(2, '0');

const todayISO = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const todayLabel = `${dayNames[day]}, ${monthNames[now.getMonth()]} ${now.getDate()}, ${now.getFullYear()}`;

const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);
const yesterdayISO = `${yesterday.getFullYear()}-${pad(yesterday.getMonth()+1)}-${pad(yesterday.getDate())}`;

// Week number
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNumber = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);

const startOfTodayISO = `${todayISO}T00:00:00Z`;
const endOfTodayISO   = `${todayISO}T23:59:59Z`;

return [{
  json: {
    todayISO,
    todayLabel,
    yesterdayISO,
    weekNumber,
    startOfTodayISO,
    endOfTodayISO,
    generatedAt: now.toISOString()
  }
}];

// Pull data from all branches via node references
const dateCtx    = $('Code — Weekday Guard & Date Context').item.json;

// HubSpot contacts
const hsContacts = $('HubSpot — Fetch Today\'s New Leads').item.json;
const newLeads   = hsContacts?.total ?? hsContacts?.results?.length ?? 0;

// HubSpot deals
const hsDeals    = $('HubSpot — Fetch Open Deals Pipeline').item.json;
const dealsList  = hsDeals?.results || [];
const openDeals  = hsDeals?.total ?? dealsList.length;
const pipelineValue = dealsList.reduce((sum, d) => sum + parseFloat(d.properties?.amount || 0), 0);

// Zendesk
const zdData       = $('Zendesk — Fetch Today\'s Support Tickets').item.json;
const ticketsToday = zdData?.count ?? zdData?.results?.length ?? 0;
const openTickets  = zdData?.results?.filter(t => t.status === 'open' || t.status === 'new').length ?? 0;

// Pipedrive
const pdData      = $('Pipedrive — Fetch Sales Pipeline').item.json;
const pdDeals     = pdData?.data || [];
const dealsWon    = pdDeals.filter(d => d.status === 'won').length;
const dealsLost   = pdDeals.filter(d => d.status === 'lost').length;
const pdPipeValue = pdDeals.reduce((sum, d) => sum + (d.value || 0), 0);

// Format helpers
const fmtCurrency = n => '$' + n.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });

return [{
  json: {
    ...dateCtx,
    metrics: {
      hubspot: {
        new_leads:      newLeads,
        open_deals:     openDeals,
        pipeline_value: fmtCurrency(pipelineValue)
      },
      zendesk: {
        tickets_today: ticketsToday,
        open_tickets:  openTickets
      },
      pipedrive: {
        deals_won:      dealsWon,
        deals_lost:     dealsLost,
        pipeline_value: fmtCurrency(pdPipeValue)
      }
    },
    rawPipelineValue: pipelineValue,
    rawPdPipeValue: pdPipeValue
  }
}];

const confResp  = $input.first().json;
const metricsData = $('Code — Compile All CRM Metrics').item.json;

// Try to extract yesterday's numbers from Confluence page body
let yesterdayMetrics = { new_leads: 0, open_deals: 0, tickets_today: 0, deals_won: 0 };

try {
  const bodyHtml = confResp?.results?.[0]?.body?.storage?.value || '';
  // Parse key numbers with regex on the stored HTML
  const extractNum = (html, label) => {
    const rx = new RegExp(`${label}[^\\d]*(\\d+)`, 'i');
    const m  = html.match(rx);
    return m ? parseInt(m[1]) : 0;
  };
  yesterdayMetrics.new_leads    = extractNum(bodyHtml, 'New Leads');
  yesterdayMetrics.open_deals   = extractNum(bodyHtml, 'Open Deals');
  yesterdayMetrics.tickets_today = extractNum(bodyHtml, 'Tickets');
  yesterdayMetrics.deals_won    = extractNum(bodyHtml, 'Deals Won');
} catch(e) {
  // No yesterday page — deltas will show as N/A
}

const m = metricsData.metrics;
const delta = (today, yest) => {
  if (!yest) return '';
  const diff = today - yest;
  return diff > 0 ? ` (▲${diff} vs yesterday)` : diff < 0 ? ` (▼${Math.abs(diff)} vs yesterday)` : ' (no change)';
};

const metricsNarrative = [
  `New Leads: ${m.hubspot.new_leads}${delta(m.hubspot.new_leads, yesterdayMetrics.new_leads)}`,
  `Open Deals: ${m.hubspot.open_deals} worth ${m.hubspot.pipeline_value}`,
  `Support Tickets Today: ${m.zendesk.tickets_today}${delta(m.zendesk.tickets_today, yesterdayMetrics.tickets_today)}, Open: ${m.zendesk.open_tickets}`,
  `Sales — Won: ${m.pipedrive.deals_won}${delta(m.pipedrive.deals_won, yesterdayMetrics.deals_won)}, Lost: ${m.pipedrive.deals_lost}, Pipeline: ${m.pipedrive.pipeline_value}`
].join('\n');

return [{
  json: {
    ...metricsData,
    yesterdayMetrics,
    metricsNarrative
  }
}];

