// Poll the run until status is 'completed'
// n8n doesn't have a native poll node — we use a wait-and-retry pattern in code
const runId      = $input.first().json.id;
const threadId   = $input.first().json.thread_id;
const apiKey     = 'YOUR_OPENAI_API_KEY';

const maxAttempts = 20;
const delayMs     = 3000;

const sleep = ms => new Promise(r => setTimeout(r, ms));

let status = 'queued';
let runData = {};
let attempts = 0;

while (status !== 'completed' && status !== 'failed' && attempts < maxAttempts) {
  await sleep(delayMs);
  const resp = await fetch(
    `https://api.openai.com/v1/threads/${threadId}/runs/${runId}`,
    {
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'OpenAI-Beta': 'assistants=v2'
      }
    }
  );
  runData = await resp.json();
  status  = runData.status;
  attempts++;
}

if (status !== 'completed') {
  throw new Error(`OpenAI run did not complete. Final status: ${status}`);
}

// Fetch messages
const msgResp = await fetch(
  `https://api.openai.com/v1/threads/${threadId}/messages`,
  {
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'OpenAI-Beta': 'assistants=v2'
    }
  }
);
const msgData = await msgResp.json();

const assistantMsg = (msgData.data || []).find(m => m.role === 'assistant');
const script = assistantMsg?.content?.[0]?.text?.value || '';

if (!script) throw new Error('No script returned from OpenAI Assistant');

const prevData = $('Code — Enrich Metrics with Delta vs Yesterday').item.json;

return [{ json: { ...prevData, briefingScript: script, threadId, runId } }];

// Azure returns raw binary — wrap it properly for UploadToURL
const allData = $('Code — Poll Run & Extract Briefing Script').item.json;
const todayISO = allData.todayISO || new Date().toISOString().split('T')[0];

return [{
  json:   { ...allData },
  binary: {
    data: {
      data:          $input.first().binary?.data?.data,
      mimeType:      'audio/mpeg',
      fileName:      `daily-briefing-${todayISO}.mp3`,
      fileExtension: 'mp3'
    }
  }
}];

const uploadResp = $input.first().json;
const briefData  = $('Code — Poll Run & Extract Briefing Script').item.json;

const audioUrl =
  uploadResp?.url ??
  uploadResp?.data?.url ??
  uploadResp?.file?.url ??
  uploadResp?.link ?? '';

if (!audioUrl) throw new Error('UploadToURL returned no URL for briefing audio');

return [{ json: { ...briefData, audioUrl } }];

