// Send SMS to each leadership number via Twilio
const data    = $('Code — Store Briefing Audio URL').item.json;
const m       = data.metrics;

const TO_NUMBERS = [
  '+1XXXXXXXXXX',
  '+1XXXXXXXXXX'
];

const msgBody = [
  `📊 Daily Briefing — ${data.todayLabel}`,
  `Leads: ${m.hubspot.new_leads} | Deals: ${m.hubspot.open_deals} (${m.hubspot.pipeline_value})`,
  `Tickets: ${m.zendesk.tickets_today} open | Won: ${m.pipedrive.deals_won}`,
  `🎧 Listen: ${data.audioUrl}`
].join('\n');

const accountSid = 'YOUR_TWILIO_ACCOUNT_SID';
const authToken  = 'YOUR_TWILIO_AUTH_TOKEN';
const fromNumber = 'YOUR_TWILIO_FROM_NUMBER';
const basicAuth  = Buffer.from(`${accountSid}:${authToken}`).toString('base64');

const results = [];
for (const toNumber of TO_NUMBERS) {
  const resp = await fetch(
    `https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`,
    {
      method: 'POST',
      headers: {
        'Authorization': `Basic ${basicAuth}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: new URLSearchParams({ To: toNumber, From: fromNumber, Body: msgBody }).toString()
    }
  );
  const r = await resp.json();
  results.push({ to: toNumber, sid: r.sid, status: r.status });
}

return [{ json: { ...data, twilioResults: results } }];

